const testCase = $('Code — Test Cases').item.json;
const rawContent = $json.choices[0].message.content;

let actual;
try {
  // Strip markdown code blocks if present
  const cleaned = rawContent.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  actual = JSON.parse(cleaned);
} catch(e) {
  return [{ json: {
    id: testCase.id,
    language: testCase.language,
    message: testCase.message,
    expected_category: testCase.expected_category,
    expected_priority: testCase.expected_priority,
    expected_route: testCase.expected_route,
    expected_needs_review: testCase.expected_needs_review,
    actual_category: 'PARSE_ERROR',
    actual_priority: 'PARSE_ERROR',
    actual_route: 'PARSE_ERROR',
    actual_confidence: 0,
    actual_needs_review: true,
    category_correct: false,
    priority_correct: false,
    route_correct: false,
    needs_review_correct: false,
    notes: 'Parse error: ' + rawContent.substring(0, 100)
  }}];
}

const needsReview = actual.priority === 'critical' || actual.confidence < 0.8;
const catCorrect = actual.category === testCase.expected_category;
const priCorrect = actual.priority === testCase.expected_priority;
const routeCorrect = actual.route === testCase.expected_route;
const reviewCorrect = needsReview === testCase.expected_needs_review;

return [{ json: {
  id: testCase.id,
  language: testCase.language,
  message: testCase.message,
  expected_category: testCase.expected_category,
  expected_priority: testCase.expected_priority,
  expected_route: testCase.expected_route,
  expected_needs_review: testCase.expected_needs_review,
  actual_category: actual.category || 'null',
  actual_priority: actual.priority || 'null',
  actual_route: actual.route || 'null',
  actual_confidence: actual.confidence || 0,
  actual_needs_review: needsReview,
  category_correct: catCorrect,
  priority_correct: priCorrect,
  route_correct: routeCorrect,
  needs_review_correct: reviewCorrect,
  notes: testCase.edge_case || ''
}}];
